---

## Step 5: Calculate New APP Mass

```
Refactored Code:
type Cell = [number, number];

const cellKey = (x: number, y: number): string => `${x},${y}`;

const countLiveNeighbors = (x: number, y: number, alive: Set<string>): number => {
  let count = 0;
  for (let dx = -1; dx <= 1; dx++) {
    for (let dy = -1; dy <= 1; dy++) {
      if (dx === 0 && dy === 0) continue;
      if (alive.has(cellKey(x + dx, y + dy))) count++;
    }
  }
  return count;
};

export function nextGeneration(cells: Cell[]): Cell[] {
  const alive = new Set(cells.map(([x, y]) => cellKey(x, y)));

  return cells.filter(([x, y]) => {
    const neighbors = countLiveNeighbors(x, y, alive);
    return neighbors === 2 || neighbors === 3;
  });
}
```

